"""Firmware handler for version 6.34.x (tested with 6.34.7)"""

import re
from bs4 import BeautifulSoup

from .base import FirmwareHandler
from .. import parser


class FirmwareHandler_6_34(FirmwareHandler):
    """Handler for AT&T BGW320-500 firmware 6.34.x series.

    Tested with firmware version 6.34.7 (March 2026).
    """

    def __init__(self):
        super().__init__()
        self.version = "6.34.x"

    def get_page_paths(self):
        """Return page paths for firmware 6.34.x"""
        return {
            'dhcp': '/cgi-bin/dhcpserver.ha',
            'ipalloc': '/cgi-bin/ipalloc.ha',
            'sysinfo': '/cgi-bin/sysinfo.ha',
            'devices': '/cgi-bin/devices.ha',
            'home': '/cgi-bin/home.ha',
        }

    def parse_dhcp_page(self, html):
        """Parse DHCP server configuration from dhcpserver.ha.

        Extracts both private LAN and public subnet settings.

        Args:
            html: HTML content from dhcpserver.ha page

        Returns:
            Dictionary with DHCP configuration:
            {
                'private_lan': {...},
                'public_subnet': {...}
            }
        """
        config = {
            'private_lan': {},
            'public_subnet': {}
        }

        # Private LAN settings
        config['private_lan']['ipaddr'] = parser.extract_input_value(html, 'ipaddr')
        config['private_lan']['ipmask'] = parser.extract_input_value(html, 'ipmask')
        config['private_lan']['dhcp'] = parser.extract_select_value(html, 'dhcp')
        config['private_lan']['dhcpstart'] = parser.extract_input_value(html, 'dhcpstart')
        config['private_lan']['dhcpend'] = parser.extract_input_value(html, 'dhcpend')
        config['private_lan']['dhcpday'] = parser.extract_input_value(html, 'dhcpday')
        config['private_lan']['dhcphour'] = parser.extract_input_value(html, 'dhcphour')
        config['private_lan']['dhcpmin'] = parser.extract_input_value(html, 'dhcpmin')
        config['private_lan']['dhcpsec'] = parser.extract_input_value(html, 'dhcpsec')

        # Public subnet settings
        config['public_subnet']['pubsub'] = parser.extract_select_value(html, 'pubsub')
        config['public_subnet']['ain'] = parser.extract_select_value(html, 'ain')
        config['public_subnet']['pubipaddr'] = parser.extract_input_value(html, 'pubipaddr')
        config['public_subnet']['pubmask'] = parser.extract_input_value(html, 'pubmask')
        config['public_subnet']['pubdhcpstart'] = parser.extract_input_value(html, 'pubdhcpstart')
        config['public_subnet']['pubdhcpend'] = parser.extract_input_value(html, 'pubdhcpend')
        config['public_subnet']['primpool'] = parser.extract_radio_value(html, 'primpool')

        # Cascaded router
        config['cascaded_router'] = parser.extract_select_value(html, 'cr')

        return config

    def parse_ipalloc_page(self, html):
        """Parse IP allocation table from ipalloc.ha.

        Args:
            html: HTML content from ipalloc.ha page

        Returns:
            Dictionary with IP allocation data:
            {
                'allocations': {
                    'mac_address': {
                        'ip': '...',
                        'status': 'Online/Offline',
                        'allocation_type': 'DHCP/Fixed Allocation'
                    }
                }
            }
        """
        soup = BeautifulSoup(html, 'html.parser')
        allocations = {}

        # Find the IP allocation table
        # The table contains rows with: IP/Name, MAC, Status, Allocation Type
        rows = soup.find_all('tr')

        for row in rows:
            cells = row.find_all('td')
            if len(cells) >= 4:
                # Extract text from cells, stripping HTML
                ip_or_name = cells[0].get_text(strip=True)
                mac = cells[1].get_text(strip=True).lower()
                status = cells[2].get_text(strip=True)
                alloc_type = cells[3].get_text(strip=True)

                # Clean up IP (may have hostname appended)
                ip_match = re.search(r'(\d+\.\d+\.\d+\.\d+)', ip_or_name)
                if ip_match:
                    ip = ip_match.group(1)
                else:
                    ip = ip_or_name

                # Validate MAC address format
                if mac and re.match(r'^[0-9a-f]{2}(:[0-9a-f]{2}){5}$', mac):
                    allocations[mac] = {
                        'ip': ip,
                        'status': status,
                        'allocation_type': alloc_type
                    }

        return {'allocations': allocations}

    def build_dhcp_form_data(self, html, public_subnet_config=None, private_lan_config=None):
        """Build form data for submitting DHCP configuration changes.

        Args:
            html: Current HTML from dhcpserver.ha page
            public_subnet_config: Dict with public subnet settings to apply (optional)
            private_lan_config: Dict with private LAN settings to apply (optional)

        Returns:
            Dictionary of form fields ready to POST
        """
        # Extract nonce
        nonce = parser.extract_nonce(html)
        if not nonce:
            raise ValueError("Could not extract nonce from DHCP page")

        # Parse current configuration
        current = self.parse_dhcp_page(html)

        # Build form data, merging current with requested changes
        form_data = {
            'nonce': nonce,
            # Private LAN settings
            'ipaddr': current['private_lan']['ipaddr'] or '192.168.1.254',
            'ipmask': current['private_lan']['ipmask'] or '255.255.255.0',
            'dhcp': current['private_lan']['dhcp'] or 'on',
            'dhcpstart': current['private_lan']['dhcpstart'] or '192.168.1.64',
            'dhcpend': current['private_lan']['dhcpend'] or '192.168.1.253',
            'dhcpday': current['private_lan']['dhcpday'] or '1',
            'dhcphour': current['private_lan']['dhcphour'] or '0',
            'dhcpmin': current['private_lan']['dhcpmin'] or '0',
            'dhcpsec': current['private_lan']['dhcpsec'] or '0',
            # Public subnet settings
            'pubsub': current['public_subnet']['pubsub'] or 'off',
            'ain': current['public_subnet']['ain'] or 'off',
            'pubipaddr': current['public_subnet']['pubipaddr'] or '',
            'pubmask': current['public_subnet']['pubmask'] or '',
            'pubdhcpstart': current['public_subnet']['pubdhcpstart'] or '',
            'pubdhcpend': current['public_subnet']['pubdhcpend'] or '',
            'primpool': current['public_subnet']['primpool'] or 'private',
            # Cascaded router
            'cr': current['cascaded_router'] or 'off',
            # Submit button
            'Save': 'Save',
        }

        # Override with requested private LAN changes
        if private_lan_config:
            for key, value in private_lan_config.items():
                if value is not None and key in form_data:
                    form_data[key] = value

        # Override with requested public subnet changes
        if public_subnet_config:
            for key, value in public_subnet_config.items():
                if value is not None and key in form_data:
                    form_data[key] = value

        return form_data

    def build_ipalloc_form_data(self, html, mac_address):
        """Build form data for allocating a specific MAC address.

        Args:
            html: Current HTML from ipalloc.ha page
            mac_address: MAC address to allocate (e.g., "bc:24:11:8f:08:b4")

        Returns:
            Dictionary of form fields ready to POST
        """
        nonce = parser.extract_nonce(html)
        if not nonce:
            raise ValueError("Could not extract nonce from IP allocation page")

        # The button name for allocation is "Allocate_<mac>"
        button_name = f"Allocate_{mac_address}"

        return {
            'nonce': nonce,
            button_name: 'Allocate'
        }
